// import React from "react";
import "../App.css";
import { useNavigate } from "react-router-dom";
import * as React from "react";
import Card from "@mui/material/Card";
import CardContent from "@mui/material/CardContent";
import CardMedia from "@mui/material/CardMedia";
import Typography from "@mui/material/Typography";
import CardActionArea from "@mui/material/CardActionArea";

export default function LandingPage() {
  const router = useNavigate();

  return (
    <div className="landingPageContainer">
      <nav>
        <div className="navHeader">
          <img src="/video_full_logo.gif" alt="" />
        </div>
        <div className="navList">
          <p
            onClick={() => {
              router("/ash");
            }}
          >
            Join as Guest
          </p>
          <p
            onClick={() => {
              router("/auth");
            }}
          >
            Register
          </p>
          <div
            onClick={() => {
              router("/auth");
            }}
            role="button"
          >
            <p>Login</p>
          </div>
        </div>
      </nav>

      <div className="landingMainContainer">
        <div>
          <h1>
            <span style={{ color: "#D97500" }}>Connect</span> with your{" "}
            <span style={{ color: "#ed2424" }}>Loved</span> ones
          </h1>

          <p>Cover the distance by A_Call</p>
          <div
            style={{ cursor: "pointer" }}
            onClick={() => router("/auth")}
            role="button"
            tabIndex={0}
            onKeyPress={(e) => {
              if (e.key === "Enter" || e.key === " ") router("/auth");
            }}
          >
            Get Started
          </div>
        </div>

        <div>
          <Card sx={{ maxWidth: 345 }} className="card1" >
            <CardActionArea>
              <CardMedia
                component="img"
                height="17"
                image="https://img.freepik.com/free-photo/friends-family-making-videocall-catching-up_23-2149019117.jpg?semt=ais_hybrid&w=740"
                alt=""
              />
              <CardContent>
                <Typography gutterBottom variant="h5" component="div">
                  Realtime Video calling
                </Typography>
                {/* <Typography variant="body2" sx={{ color: "text.secondary" }}>
                  Lizards are a widespread group of squamate reptiles, with over
                  6,000 species, ranging across all continents except Antarctica
                </Typography> */}
              </CardContent>
            </CardActionArea>
          </Card>

          <Card sx={{ maxWidth: 345 }} className="card2">
            <CardActionArea>
              <CardMedia
                component="img"
                height="170"
                image="https://i.ytimg.com/vi/nKXFKA6FXnI/maxresdefault.jpg"
                alt=""
              />
              <CardContent>
                <Typography gutterBottom variant="h5" component="div">
                  Connect & Chat
                </Typography>
                {/* <Typography variant="body2" sx={{ color: "text.secondary" }}>
                  Lizards are a widespread group of squamate reptiles, with over
                  6,000 species, ranging across all continents except Antarctica
                </Typography> */}
              </CardContent>
            </CardActionArea>
          </Card>

          <Card sx={{ maxWidth: 345 }} className="card3">
            <CardActionArea>
              <CardMedia
                component="img"
                height="170"
                image="https://i.ytimg.com/vi/nKXFKA6FXnI/maxresdefault.jpg"
                alt=""
              />
              <CardContent>
                <Typography gutterBottom variant="h5" component="div">
                  Compressing the distances
                </Typography>
                {/* <Typography variant="body2" sx={{ color: "text.secondary" }}>
                  Lizards are a widespread group of squamate reptiles, with over
                  6,000 species, ranging across all continents except Antarctica
                </Typography> */}
              </CardContent>
            </CardActionArea>
          </Card>
        </div>
      </div>
    </div>
  );
}
